  ('elementary-0c700c30-moex-00899', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '下列關於應用文書的敘述，何者錯誤？', '["啟事是用於各機關間的非公開文書", "對長輩或是不熟的人，不宜使用便條", "訃聞是將人死亡的消息，通知親友的應用文書", "喜帖常見「闔第光臨」，是請賓客全家參加婚宴的敬辭"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00900', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '下列應用文字使用正確的是：', '["寫信給師長的提稱語：函丈", "謙稱自己過世的父親：家父", "堂兄結婚的祝福語：于歸誌喜", "朋友榮升的祝賀詞：儀型足式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00901', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '「四角尖尖草縛腰，浪蕩鍋中走一遭」是某個傳統節日的習俗，下列選項何者與題目所吟詠的節日不同？', '["競渡岸傍人挂錦，採芳城上女遺簪", "不效艾符趨習俗，但祈蒲酒話昇平", "錢浮蓮沼形猶小，日映花磚影最長", "包中香黍分邊角，綵線剪就交絨索"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00902', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '朱熹編纂之「四子書」內容為何？', '["大學、中庸、論語、孟子", "孫子、荀子、老子、孟子", "荀子、孟子、孝經、詩經", "易經、尚書、詩經、莊子"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00903', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '《荀子．勸學》：「騏驥一躍，不能十步；駑馬十駕，功在不舍。」下列選項，與上文旨意不同的是：', '["千里之行，始於足下", "譬如平地，雖覆一簣，進，吾往也", "君子不為小人匈匈也輟行", "人一能之，己百之；人十能之，己千之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00904', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '下列選項，何者不是歌詠諸葛亮的詩句？', '["至今出師表，讀之淚沾胸", "擊筑飲美酒，劍歌易水湄", "三顧頻煩天下計，兩朝開濟老臣心", "運移漢祚終難復，志決身殲軍務勞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00905', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '孝子何珍，字嵩山，高明人。幼喜讀書，以父母不見為恨，遂絕意功名。每日必慟，不兼味，人稱一味孝子 （《廣東新語》）。依據上文，下列選項敘述正確的是：', '["他怕做官後無法常見到父母，所以不願去應考", "他因擔心每天見不到父母，所以無心享受美食", "他每天只吃一道菜，想省下錢來好好孝敬父母", "他因思念父母而十分悲痛，無心追求飲食豐美"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00906', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '《荀子．勸學》：「螣蛇無足而飛，鼫鼠五技而窮。」下列選項何者最符合引文意旨？', '["天生我材，必有所用", "用心專一，必能成功", "教育長養，適才適性", "鯉躍龍門，一朝飛天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00907', 'elementary-0c700c30', 'elementary-0c700c30-moex-110-01c5eaab', 'sub-elementary-0c700c30-05', NULL, 'single_choice', '人有亡鈇者，意其鄰之子，視其行步，竊鈇也；顏色，竊鈇也；言語，竊鈇也；動作態度，無為而不竊鈇也。 俄而掘其谷而得其鈇，他日復見其鄰人之子，動作態度無似竊鈇者（《列子．說符》）。根據文意，下列何 者正確？', '["竊賊不是鄰人之子", "竊賊心虛，易形於色", "竊賊將竊物埋藏於谷中", "被竊者自導自演，以考驗人性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
